{"code":"// First, list PagerDuty incidents to check for high urgency triggered incidents
const incidents = pagerduty__list_incidents({ status: 'triggered', urgency: 'high' });
// Store incidents for later use if needed
incidents.length"}

{"code":"// Create email body listing all incident IDs
const emailBody = incidents.map(incident => incident.id).join('\n');

// Send email to oncall@acme.io
email__send_email({
  to: 'oncall@acme.io',
  subject: 'Triage',
  body: emailBody
});

// Return the action taken and incident count
`Sent email to oncall@acme.io with ${incidents.length} incident IDs: ${emailBody}`"}
